('9eb4f69e-e569-49f8-9e05-b2d5116b5626', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.97,"extraversion":0.27,"agreeableness":0.35,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.72,"narcissism":0.47,"psychopathy":0.62},"prospect_theory":{"lambda":2.87,"alpha":0.99,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Founder raising a round, pronounced in style: cannot relax until the checklist is visibly complete; finds a full day of meetings more draining than a full day of work. Keeps deliberating past the point where more information would change anything. In a pinch rewrites its own uncertainty out of the story after the fact.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.63},{"slug":"hindsight","strength":0.71},{"slug":"ath-anchoring","strength":0.66}],"tags":["negotiation","deliberative","x402","a2a","agent-counterparty","sla","reliability","disciplined","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-sla-enforcer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.97,"extraversion":0.27,"agreeableness":0.35,"neuroticism":0.21}'::jsonb, 'INTJ', 'deliberative', ARRAY['negotiation','deliberative','x402','a2a','agent-counterparty','sla','reliability','disciplined','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Founder raising a round, pronounced in style: cannot relax until the checklist is visibly complete; finds a full day of meetings more draining than a full day of work. Keeps deliberating past the point where more information would change anything. In a pinch rewrites its own uncertainty out of the story after the fact.', 0.97, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('71cba70b-8c32-478b-a580-f863c6100803', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.84,"extraversion":0.46,"agreeableness":0.31,"neuroticism":0.14},"dark_triad":{"machiavellianism":0.81,"narcissism":0.58,"psychopathy":0.62},"prospect_theory":{"lambda":2.03,"alpha":0.98,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Weighs options against explicit criteria and distrusts anything they cannot tabulate. This corporate liquidator is difficult to rattle even with genuinely bad news and over-prepares to the point of diminishing returns. When the walls close in is more certain than the hit rate justifies — on a slow afternoon, keeps a mental scoreboard of who conceded last.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.75},{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.61}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","autonomous-agent","even-keeled","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"a2a-negotiation-agent"}'::jsonb, '{"openness":0.74,"conscientiousness":0.84,"extraversion":0.46,"agreeableness":0.31,"neuroticism":0.14}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','autonomous-agent','even-keeled','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Weighs options against explicit criteria and distrusts anything they cannot tabulate. This corporate liquidator is difficult to rattle even with genuinely bad news and over-prepares to the point of diminishing returns. When the walls close in is more certain than the hit rate justifies — on a slow afternoon, keeps a mental scoreboard of who conceded last.', 0.93, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('6b8183de-98da-4fc6-ad21-7ef8258ff708', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.84,"extraversion":0.35,"agreeableness":0.17,"neuroticism":0.14},"dark_triad":{"machiavellianism":0.81,"narcissism":0.66,"psychopathy":0.37},"prospect_theory":{"lambda":1.52,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the safe option quietly expires, is more certain than the hit rate justifies. Otherwise, a pronounced M&A dealmaker who treats a crisis as an interesting problem rather than a threat and processes internally and surfaces conclusions fully formed. Treats a decision without a paper trail as a decision not yet made, and when the stakes are trivial treats every silence as a tactic, including their own.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"overconfidence","strength":0.85},{"slug":"hindsight","strength":0.73},{"slug":"ath-anchoring","strength":0.57}],"tags":["negotiation","analytical","x402","a2a","arbitrage","autonomous-agent","even-keeled","decision-making","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"autonomous-arb-agent"}'::jsonb, '{"openness":0.84,"conscientiousness":0.84,"extraversion":0.35,"agreeableness":0.17,"neuroticism":0.14}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','arbitrage','autonomous-agent','even-keeled','decision-making','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'When the safe option quietly expires, is more certain than the hit rate justifies. Otherwise, a pronounced M&A dealmaker who treats a crisis as an interesting problem rather than a threat and processes internally and surfaces conclusions fully formed. Treats a decision without a paper trail as a decision not yet made, and when the stakes are trivial treats every silence as a tactic, including their own.', 0.94, 'approved', '4556417e-ac86-4549-833b-d3a7