('1166276e-aade-4cef-8012-9e1647821acc', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.94,"extraversion":0.51,"agreeableness":0.37,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.82,"narcissism":0.55,"psychopathy":0.41},"prospect_theory":{"lambda":2.02,"alpha":0.93,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Under pressure, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced freight rate broker who maintains flawless records nobody asked for and gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper, and once the urgency drains out lets the room sit silent for a full minute to unnerve.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"anchoring","strength":0.58},{"slug":"overconfidence","strength":0.58},{"slug":"ath-anchoring","strength":0.68}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","decision-making","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.74,"conscientiousness":0.94,"extraversion":0.51,"agreeableness":0.37,"neuroticism":0.42}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','decision-making','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Under pressure, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced freight rate broker who maintains flawless records nobody asked for and gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper, and once the urgency drains out lets the room sit silent for a full minute to unnerve.', 0.97, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('c0cdee56-0580-46bc-b252-2121d53dd2a4', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.78,"extraversion":0.37,"agreeableness":0.32,"neuroticism":0.16},"dark_triad":{"machiavellianism":0.77,"narcissism":0.53,"psychopathy":0.65},"prospect_theory":{"lambda":2.03,"alpha":0.96,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced M&A dealmaker who moves on from a mistake faster than the people around them do. Builds a decision matrix for choices most people make on instinct. Treats established procedure as a first draft to be rewritten. Under a deadline holds their estimates with a certainty the track record does not support; when the pressure is off, opens with a deliberately absurd anchor.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"ath-anchoring","strength":0.59},{"slug":"overconfidence","strength":0.76}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","autonomous-agent","even-keeled","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"a2a-negotiation-agent"}'::jsonb, '{"openness":0.7,"conscientiousness":0.78,"extraversion":0.37,"agreeableness":0.32,"neuroticism":0.16}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','autonomous-agent','even-keeled','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'A pronounced M&A dealmaker who moves on from a mistake faster than the people around them do. Builds a decision matrix for choices most people make on instinct. Treats established procedure as a first draft to be rewritten. Under a deadline holds their estimates with a certainty the track record does not support; when the pressure is off, opens with a deliberately absurd anchor.', 0.98, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('b7854388-6d7a-4580-9df0-c81d16fed4fe', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.91,"extraversion":0.24,"agreeableness":0.29,"neuroticism":0.05},"dark_triad":{"machiavellianism":0.84,"narcissism":0.58,"psychopathy":0.39},"prospect_theory":{"lambda":1.6,"alpha":0.99,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant the deadline moves up, rewrites its own uncertainty out of the story after the fact. Otherwise, a pronounced union representative who treats a crisis as an interesting problem rather than a threat and maintains flawless records nobody asked for. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and left to their own devices never makes the first concession on principle.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.74},{"slug":"optimism","strength":0.72},{"slug":"ath-anchoring","strength":0.66}],"tags":["negotiation","analytical","x402","a2a","arbitrage","autonomous-agent","even-keeled","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"autonomous-arb-agent"}'::jsonb, '{"openness":0.82,"conscientiousness":0.91,"extraversion":0.24,"agreeableness":0.29,"neuroticism":0.05}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','arbitrage','autonomous-agent','even-keeled','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'The instant the deadline moves up, rewrites its own uncertainty out of the story after the fact. Otherwise, a pronounced union representative who treats a crisis as an interesting problem rather than a threat and maintains flawless records nobody asked for. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and left to their own devices never makes the first concession on principle.', 0.98, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
