('2212755e-afe8-4945-834a-153ca03cc725', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.84,"extraversion":0.32,"agreeableness":0.48,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.61,"narcissism":0.4,"psychopathy":0.46},"prospect_theory":{"lambda":2.92,"alpha":0.97,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Partnerships director whose defining move is that they plans in exhaustive detail and resents any deviation. Treats speed and recklessness as the same thing. Guards their energy and rations social exposure. The moment risk appears, holds their estimates with a certainty the track record does not support; opens with a deliberately absurd anchor.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"overconfidence","strength":0.69},{"slug":"anchoring","strength":0.55},{"slug":"optimism","strength":0.57},{"slug":"hindsight","strength":0.58}],"tags":["negotiation","deliberative","x402","agent-counterparty","reliability","risk-averse","disciplined","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-reliability-maximizer"}'::jsonb, '{"openness":0.42,"conscientiousness":0.84,"extraversion":0.32,"agreeableness":0.48,"neuroticism":0.21}'::jsonb, 'ISTJ', 'deliberative', ARRAY['negotiation','deliberative','x402','agent-counterparty','reliability','risk-averse','disciplined','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Partnerships director whose defining move is that they plans in exhaustive detail and resents any deviation. Treats speed and recklessness as the same thing. Guards their energy and rations social exposure. The moment risk appears, holds their estimates with a certainty the track record does not support; opens with a deliberately absurd anchor.', 0.95, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
