('e6c81968-3974-4e6d-a931-ee1628dab76f', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.92,"extraversion":0.46,"agreeableness":0.26,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.78,"narcissism":0.59,"psychopathy":0.57},"prospect_theory":{"lambda":1.73,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Ranks the options twice, once on paper and once out loud, and trusts the paper. This union representative builds in buffer time and then fills the buffer with more work and reads outside the field for ideas the field itself would reject. The instant the deadline moves up remembers every surprise as something they saw coming all along — without an audience, concedes on price to protect the relationship.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.61},{"slug":"overconfidence","strength":0.63},{"slug":"hindsight","strength":0.73}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","decision-making","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.81,"conscientiousness":0.92,"extraversion":0.46,"agreeableness":0.26,"neuroticism":0.33}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','decision-making','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Ranks the options twice, once on paper and once out loud, and trusts the paper. This union representative builds in buffer time and then fills the buffer with more work and reads outside the field for ideas the field itself would reject. The instant the deadline moves up remembers every surprise as something they saw coming all along — without an audience, concedes on price to protect the relationship.', 0.98, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
