('c3504ab5-8f33-43aa-9fe6-82aa12e7a2da', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.57,"narcissism":0.37,"psychopathy":0.42},"prospect_theory":{"lambda":3.03,"alpha":0.92,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"M&A dealmaker, pronounced in style: plans in exhaustive detail and resents any deviation; stays flat when the numbers go red. Wants the second-order consequences mapped before the first move is made. Under a deadline is surprised in the moment and certain in the retelling.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"overconfidence","strength":0.55},{"slug":"ath-anchoring","strength":0.61},{"slug":"optimism","strength":0.63},{"slug":"hindsight","strength":0.65}],"tags":["negotiation","deliberative","x402","agent-counterparty","reliability","risk-averse","disciplined","decision-making","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-reliability-maximizer"}'::jsonb, '{"openness":0.56,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.25}'::jsonb, 'INFJ', 'deliberative', ARRAY['negotiation','deliberative','x402','agent-counterparty','reliability','risk-averse','disciplined','decision-making','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'M&A dealmaker, pronounced in style: plans in exhaustive detail and resents any deviation; stays flat when the numbers go red. Wants the second-order consequences mapped before the first move is made. Under a deadline is surprised in the moment and certain in the retelling.', 0.98, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('28789a5a-2aff-490a-b40f-3d632d1a2374', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.85,"extraversion":0.46,"agreeableness":0.19,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.83,"narcissism":0.64,"psychopathy":0.64},"prospect_theory":{"lambda":1.92,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Weighs options against explicit criteria and distrusts anything they cannot tabulate. This salary negotiator maintains flawless records nobody asked for and is difficult to rattle even with genuinely bad news. The moment risk appears remembers every surprise as something they saw coming all along — in the pattern nobody else tracks, concedes on price to protect the relationship.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.67},{"slug":"hindsight","strength":0.7}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.77,"conscientiousness":0.85,"extraversion":0.46,"agreeableness":0.19,"neuroticism":0.32}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'Weighs options against explicit criteria and distrusts anything they cannot tabulate. This salary negotiator maintains flawless records nobody asked for and is difficult to rattle even with genuinely bad news. The moment risk appears remembers every surprise as something they saw coming all along — in the pattern nobody else tracks, concedes on price to protect the relationship.', 0.94, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
('0108b3a4-46e9-4bdd-88ce-9e8314cabe1a', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.82,"extraversion":0.49,"agreeableness":0.38,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.8,"narcissism":0.54,"psychopathy":0.47},"prospect_theory":{"lambda":1.78,"alpha":0.97,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A steady licensing agent who treats a missed deadline as a personal failure regardless of cause. Treats a decision without a paper trail as a decision not yet made. Chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up is surprised in the moment and certain in the retelling; day to day, writes the walk-away number down before the call starts.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.54},{"slug":"hindsight","strength":0.57}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","cognition","a2a-commerce","skill-pricing","retry-etiquette","sla-dispute"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.72,"conscientiousness":0.82,"extraversion":0.49,"agreeableness":0.38,"neuroticism":0.39}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','cognition','a2a-commerce','skill-pricing','retry-etiquette','sla-dispute']::text[], 'A steady licensing agent who treats a missed deadline as a personal failure regardless of cause. Treats a decision without a paper trail as a decision not yet made. Chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up is surprised in the moment and certain in the retelling; day to day, writes the walk-away number down before the call starts.', 0.98, 'approved', '4556417e-ac86-4549-833b-d3a75bd358ee'),
